44	func (v *defaultValidator) ValidateStruct(obj any) error {
45		if obj == nil {
46			return nil
47		}
48	
49		value := reflect.ValueOf(obj)
50		switch value.Kind() {
51		case reflect.Ptr:
52			if value.Elem().Kind() != reflect.Struct {
53				return v.ValidateStruct(value.Elem().Interface())
54			}
55			return v.validateStruct(obj)
56		case reflect.Struct:
57			return v.validateStruct(obj)
58		case reflect.Slice, reflect.Array:
59			count := value.Len()
60			validateRet := make(SliceValidationError, 0)
61			for i := range count {
62				if err := v.ValidateStruct(value.Index(i).Interface()); err != nil {
63					validateRet = append(validateRet, err)
64				}
65			}
66			if len(validateRet) == 0 {
67				return nil
68			}
69			return validateRet
70		default:
71			return nil
72		}
73	}
